// // This module implements a 2-bit wide, 2-to-1 multiplexer with a 1-bit select input.
// The output Y is determined by the 1-bit select signal S.
// When S is 0, Y is B.
// When S is 1, Y is A.
module mux_2to1_2bit (A, B, S, Y);
input [1:0] A, B;
input S;
output [1:0] Y;

assign Y = S ? B : A;

endmodule

